import { React, useEffect, useState } from 'react'
import { Box, Card, CardContent, CardHeader, Container, Grid, makeStyles, MenuItem } from '@material-ui/core'
import SubjectCards from '../components/SubjectCards'
import axios from 'axios'

import Cookies from 'js-cookie'
import { useNavigate } from 'react-router-dom'
import StudentFeed from '../pages/StudentFeed'


const useStyle = makeStyles(theme => {
    return {
        root: {
            display: 'flex'
        }
    }
});



export default function StudentDashboard() {

    const classes = useStyle();

    const navigate = useNavigate();
    const Cookie = Cookies.get('studentID');

    const [noClassroom, setNoClassroom] = useState(true);

    function sessionCheck() {
        if (!Cookie) {
            navigate('/');
        }
    }

    function showStudentsInfo() {
        axios.post('http://localhost:80/api/getStudents.php', Cookie)
            .then((response) => {
                if (response.data) {
                    Cookies.set('userName', response.data[0].firstName + ' ' + response.data[0].lastName)
                    Cookies.set('userFirstName', response.data[0].firstName)
                }

            })
            .catch(error => {
                console.log(error);
            })
    }

    
    const [subjects, setSubjects] = useState([]);

    function showClassrooms() {
        axios.post('http://localhost:80/api/getJoinedClassrooms.php', Cookie)
            .then((response) => {
                if (response.data == 0) {
                    setNoClassroom(true);
                } else {
                    setSubjects(response.data)
                    setNoClassroom(false);
                }
            })
            .catch(err => console.log(err))
    }
    

    useEffect(() => {
        sessionCheck();
        showStudentsInfo();
        showClassrooms();
    }, []);



    const [showDesignatedClassroom, setShowDesignatedClassroom] = useState(true);


    return (
        <Box>
            {
                noClassroom ?

                    <MenuItem disabled>
                        You have no classroom yet.
                    </MenuItem>

                    :

                    <Container className={classes.root}>
                        <Grid container spacing={10}>
                            {subjects.map(subject => (
                                <Grid item xs={12} sm={6} lg={3} zeroMinWidth key={subject.id}>
                                    {
                                        showDesignatedClassroom ? 

                                        <SubjectCards subject={subject} onClick={() => {setShowDesignatedClassroom(false)}} />

                                        :

                                        <StudentFeed subject={subject} />
                                    }


                                    

                                </Grid>
                            ))}
                        </Grid>
                    </Container>

            }
        </Box>
    )
}
